// Auto-generated — amos (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const AMOS_NVI: Record<number, string[]> = {
  1: ["Estas son las palabras de Amós, pastor de Tecoa. Es la visión que recibió acerca de Israel dos años antes del terremoto, cuando Uzías era rey de Judá, y Jeroboán hijo de Joás era rey de Israel.","Amós dijo: «Ruge el SEÑOR desde Sión; truena su voz desde Jerusalén. Los pastizales de los pastores quedan asolados, y se seca la cumbre del Carmelo».","Así dice el SEÑOR: «Porque los delitos de Damasco han llegado a su colmo,[1] no revocaré su castigo. Porque trillaron a Galaad con trillos de hierro,","yo enviaré fuego contra el palacio de Jazael, que consumirá las fortalezas de Ben Adad.","Romperé el cerrojo de la puerta de Damasco, destruiré al que reina en el valle de Avén[2] y al que empuña el cetro en Bet Edén. Y el pueblo de Siria será desterrado a Quir», dice el SEÑOR.","Así dice el SEÑOR: «Los delitos de Gaza han llegado a su colmo; por tanto, no revocaré su castigo: Porque desterraron a poblaciones enteras para venderlas a Edom,","yo enviaré fuego contra los muros de Gaza, que consumirá sus fortalezas.","Destruiré al que reina en Asdod y al que empuña el cetro en Ascalón. Volveré mi mano contra Ecrón, y perecerá hasta el último de los filisteos», dice el SEÑOR omnipotente.","Así dice el SEÑOR: «Los delitos de Tiro han llegado a su colmo; por tanto, no revocaré su castigo: Porque le vendieron a Edom poblaciones enteras de cautivos, olvidando así una alianza entre hermanos,","yo enviaré fuego contra los muros de Tiro, que consumirá sus fortalezas».","Así dice el SEÑOR: «Los delitos de Edom han llegado a su colmo; por tanto, no revocaré su castigo: Porque sin mostrar ninguna compasión persiguieron con espada a su hermano; porque dieron rienda suelta a su ira y no dejaron de alimentar su enojo,","yo enviaré fuego contra Temán, que consumirá las fortalezas de Bosra».","Así dice el SEÑOR: «Los delitos de Amón han llegado a su colmo; por tanto, no revocaré su castigo: Porque, a fin de extender sus fronteras, a las mujeres encintas de la región de Galaad les abrieron el vientre,","yo prenderé fuego a los muros de Rabá, que consumirá sus fortalezas entre gritos de guerra en el día de la batalla, y en el rugir de la tormenta en un día de tempestad.","Su rey[3] marchará al destierro, junto con sus oficiales», dice el SEÑOR."],
  2: ["Así dice el SEÑOR: «Los delitos de Moab han llegado a su colmo; por tanto, no revocaré su castigo: Porque quemaron los huesos del rey de Edom hasta reducirlos a ceniza,","yo enviaré fuego sobre Moab, que consumirá las fortalezas de Queriot, y morirá Moab en medio del estrépito de gritos de guerra y toques de trompeta.","Destruiré al gobernante en medio de su pueblo, y junto con él mataré a todos sus oficiales», dice el SEÑOR.","Así dice el SEÑOR: «Los delitos de Judá han llegado a su colmo; por tanto, no revocaré su castigo: Porque, dejándose descarriar por sus mentiras, tras las cuales anduvieron sus antepasados, rechazaron la ley del SEÑOR y no obedecieron sus preceptos.","Por eso yo enviaré fuego contra Judá, que consumirá las fortalezas de Jerusalén».","Así dice el SEÑOR: «Los delitos de Israel han llegado a su colmo; por tanto, no revocaré su castigo: Venden al justo por monedas, y al necesitado, por un par de sandalias.","Pisotean la cabeza de los desvalidos como si fuera el polvo de la tierra, y pervierten el camino de los pobres. Padre e hijo se acuestan con la misma mujer, profanando así mi santo nombre.","Junto a cualquier altar se acuestan sobre ropa que tomaron en prenda, y el vino que han cobrado como multa lo beben en la casa de su Dios.[4]","»Todo esto, a pesar de que por ellos yo destruí a los amorreos; destruí su fruto arriba y sus raíces abajo, aunque eran altos como el cedro y fuertes como la encina.","»Yo mismo los hice subir desde Egipto, y los conduje cuarenta años por el desierto, a fin de conquistar para ustedes la tierra de los amorreos.","También levanté profetas de entre sus hijos y nazareos de entre sus jóvenes. ¿Acaso no fue así, israelitas? —afirma el SEÑOR—.","Pero ustedes les hicieron beber vino a los nazareos y les ordenaron a los profetas que no profetizaran.","»Pues bien, estoy por aplastarlos a ustedes como aplasta una carreta cargada de trigo.","Entonces no habrá escapatoria para el ágil, ni el fuerte podrá valerse de su fuerza, ni el valiente librará su vida.","El arquero no resistirá, ni escapará con vida el ágil de piernas, ni se salvará el que monta a caballo.","En aquel día huirá desnudo aun el más valiente de los guerreros», afirma el SEÑOR."],
  3: ["Oigan, israelitas, esta palabra que el SEÑOR pronuncia contra ustedes, contra toda la familia que saqué de Egipto:","«Solo a ustedes los he escogido entre todas las familias de la tierra. Por tanto, les haré pagar todas sus perversidades».","¿Pueden dos caminar juntos sin antes ponerse de acuerdo?","¿Ruge el león en la espesura sin tener presa alguna? ¿Gruñe el leoncillo en su guarida sin haber atrapado nada?","¿Cae el pájaro en la trampa sin que haya carnada? ¿Salta del suelo la trampa sin haber atrapado nada?","¿Se toca la trompeta en la ciudad sin que el pueblo se alarme? ¿Ocurrirá en la ciudad alguna desgracia que el SEÑOR no haya provocado?","En verdad, nada hace el SEÑOR omnipotente sin antes revelar sus designios a sus siervos los profetas.","Ruge el león; ¿quién no temblará de miedo? Habla el SEÑOR omnipotente; ¿quién no profetizará?","Proclamen en las fortalezas de Asdod y en los baluartes de Egipto: «Reúnanse sobre los montes de Samaria y vean cuánto pánico hay en ella, ¡cuánta opresión hay en su medio!»","«Los que acumulan en sus fortalezas el fruto de la violencia y el saqueo no saben actuar con rectitud», afirma el SEÑOR.","Por lo tanto, así dice el SEÑOR omnipotente: «Un enemigo invadirá tu tierra; echará abajo tu poderío y saqueará tus fortalezas».","Así dice el SEÑOR: «Como el pastor arrebata de las fauces del león si acaso dos patas o un pedazo de oreja, así serán rescatados los israelitas que viven en Samaria con un pedazo de una cama y la pata de un diván.[5]","»Oigan esto y testifiquen contra el pueblo de Jacob —afirma el SEÑOR omnipotente, el Dios Todopoderoso—:","»El día en que haga pagar a Israel sus delitos, destruiré los altares de Betel; los cuernos del altar serán arrancados, y caerán por tierra.","Derribaré tanto la casa de invierno como la de verano; serán destruidas las casas adornadas de marfil y serán demolidas muchas mansiones», afirma el SEÑOR."],
  4: ["Oigan esta palabra ustedes, vacas de Basán, que viven en el monte de Samaria, que oprimen a los desvalidos y maltratan a los necesitados, que dicen a sus esposos: «¡Tráigannos de beber!»","El SEÑOR omnipotente ha jurado por su santidad: «Vendrán días en que hasta la última de ustedes será arreada con garfios y arpones.","Una tras otra saldrán por las brechas del muro, y hacia Hermón serán expulsadas —afirma el SEÑOR—.","»Vayan a Betel y pequen; vayan a Guilgal y sigan pecando. Ofrezcan sus sacrificios por la mañana, y al tercer día sus diezmos.","Quemen pan leudado como ofrenda de gratitud y proclamen ofrendas voluntarias. Háganlo saber a todos, israelitas; ¡eso es lo que a ustedes les encanta! —afirma el SEÑOR omnipotente—.","»Yo les hice pasar hambre en todas sus ciudades, y los privé de pan en todos sus poblados. Con todo, ustedes no se volvieron a mí —afirma el SEÑOR—.","»Yo les retuve la lluvia cuando aún faltaban tres meses para la cosecha. En una ciudad hacía llover, pero en otra no; una parcela recibía lluvia, mientras que otra no, y se secó.","Vagando de ciudad en ciudad, iba la gente en busca de agua, pero no calmaba su sed. Con todo, ustedes no se volvieron a mí —afirma el SEÑOR—.","»Castigué sus campos con plagas y sequía; la langosta devoró sus huertos y viñedos, sus higueras y olivares. Con todo, ustedes no se volvieron a mí —afirma el SEÑOR—.","»Les mandé plagas como las de Egipto. Pasé por la espada a sus mejores jóvenes, junto con los caballos capturados. Hice que llegara hasta sus propias narices el hedor de los cadáveres. Con todo, ustedes no se volvieron a mí —afirma el SEÑOR—.","»Yo les envié destrucción como la de Sodoma y Gomorra; ¡quedaron como tizones arrebatados del fuego! Con todo, ustedes no se volvieron a mí —afirma el SEÑOR—.","»Por eso, Israel, voy a actuar contra ti; y, como voy a hacerlo, ¡prepárate, Israel, para encontrarte con tu Dios!»","He aquí el que forma las montañas, el que crea el viento, el que revela al hombre sus designios, el que convierte la aurora en tinieblas, el que marcha sobre las alturas de la tierra: su nombre es el SEÑOR Dios Todopoderoso."],
  5: ["Oye esta palabra, reino de Israel, este canto fúnebre que por ti entono:","«Ha caído la joven Israel, y no volverá a levantarse; postrada en su propia tierra, no hay quien la levante».","Así dice el SEÑOR omnipotente al reino de Israel: «La ciudad que salía a la guerra con mil hombres se quedará solo con cien, y la que salía con cien se quedará solo con diez».","Así dice el SEÑOR al reino de Israel: «Búsquenme y vivirán.","Pero no acudan a Betel, ni vayan a Guilgal, ni pasen a Berseba, porque Guilgal será llevada cautiva, y Betel, reducida a la nada».","Busquen al SEÑOR y vivirán, no sea que él caiga como fuego sobre los descendientes de José, fuego que devore a Betel sin que haya quien lo apague.","Ustedes convierten el derecho en amargura y echan por tierra la justicia.","El SEÑOR hizo las Pléyades y el Orión, convierte en aurora las densas tinieblas y oscurece el día hasta convertirlo en noche. Él convoca las aguas del mar y las derrama sobre la tierra. ¡Su nombre es el SEÑOR!","Él reduce a la nada la fortaleza y trae la ruina sobre la plaza fuerte.","Ustedes odian al que defiende la justicia en el tribunal y detestan al que dice la verdad.","Por eso, como pisotean al desvalido y le imponen tributo de grano, no vivirán en las casas de piedra labrada que han construido, ni beberán del vino de los selectos viñedos que han plantado.","¡Yo sé cuán numerosos son sus delitos, cuán grandes sus pecados! Ustedes oprimen al justo, exigen soborno y en los tribunales atropellan al necesitado.","Por eso en circunstancias como estas guarda silencio el prudente, porque estos tiempos son malos.","Busquen el bien y no el mal, y vivirán; y así estará con ustedes el SEÑOR Dios Todopoderoso, tal como ustedes lo afirman.","¡Odien el mal y amen el bien! Hagan que impere la justicia en los tribunales; tal vez así el SEÑOR, el Dios Todopoderoso, tenga compasión del remanente de José.","Por eso, así dice el SEÑOR omnipotente, el Dios Todopoderoso: «En todas las plazas se escucharán lamentos, y gritos de angustia en todas las calles. Llamarán a duelo a los campesinos, y a los llorones profesionales, a hacer lamentación.","Se escucharán lamentos en todos los viñedos cuando yo pase en medio de ti», dice el SEÑOR.","¡Ay de los que suspiran por el día del SEÑOR! ¿De qué les servirá ese día si va a ser de oscuridad y no de luz?","Será como cuando alguien huye de un león y se le viene encima un oso, o como cuando al llegar a su casa, apoya la mano en la pared y lo muerde una serpiente.","¿No será el día del SEÑOR de oscuridad y no de luz? ¡Será por cierto sombrío y sin resplandor!","«Detesto y aborrezco sus fiestas religiosas; no me agradan sus cultos solemnes.","Aunque me traigan holocaustos y ofrendas de cereal, no los aceptaré, ni prestaré atención a los sacrificios de comunión de novillos cebados.","Aleja de mí el bullicio de tus canciones; no quiero oír la música de tus cítaras.","¡Pero que fluya el derecho como las aguas, y la justicia como arroyo inagotable!","»Pueblo de Israel, ¿acaso me ofrecieron sacrificios y ofrendas durante los cuarenta años en el desierto?","Ustedes tendrán que cargar con la imagen de Sicut, su rey, y también con la de Quiyún, imágenes de esos dioses astrales que ustedes mismos se han fabricado.","Entonces los mandaré al exilio más allá de Damasco», dice el SEÑOR, cuyo nombre es Dios Todopoderoso."],
  6: ["¡Ay de los que viven tranquilos en Sión y de los que viven confiados en el monte de Samaria! ¡Ay de los notables de la nación más importante, a quienes acude el pueblo de Israel!","Pasen a Calné y obsérvenla; vayan de allí a Jamat la grande, bajen luego a Gat de los filisteos. ¿Acaso son ustedes superiores a estos reinos, o es más grande su territorio que el de ustedes?","Ustedes creen alejar el día de la desgracia, pero están acercando el imperio de la violencia.","Ustedes que se acuestan en camas incrustadas de marfil y se arrellanan en divanes; que comen corderos selectos y terneros engordados;","que, a la manera de David, improvisan canciones al son de la cítara e inventan instrumentos musicales;","que beben vino en tazones y se perfuman con las esencias más finas sin afligirse por la ruina de José,","marcharán a la cabeza de los desterrados, y así terminará el banquete de los holgazanes.","El SEÑOR omnipotente jura por sí mismo; esto afirma el SEÑOR Dios Todopoderoso: «Yo detesto la arrogancia de Jacob; yo aborrezco sus fortalezas; por eso entregaré la ciudad al enemigo, con todo lo que hay en ella».","Sucederá que, si en una casa quedan diez hombres con vida, todos morirán.","Y, cuando vengan a la casa para levantar los cadáveres y quemarlos, algún pariente le preguntará a otro que ande en la casa: «¿Queda alguien más contigo?» Y aquel le responderá: «No». Entonces le dirá: «¡Cállate! No vayamos a mencionar el nombre del SEÑOR».","Mira, el SEÑOR da la orden de golpear la casa grande hasta hacerla añicos y de hacer trizas la casa pequeña.","¿Acaso galopan los caballos por las rocas o se ara en estas con bueyes? Pero ustedes han convertido el derecho en veneno, y en amargura el fruto de la justicia.","Ustedes se regocijan por la conquista de Lo Debar[6] y agregan: «¿No fue con nuestras propias fuerzas como nos apoderamos de Carnayin?»[7]","«Por tanto, pueblo de Israel, voy a levantar contra ti a una nación que te oprimirá desde Lebó Jamat[8] hasta el torrente del Arabá», afirma el SEÑOR, el Dios Todopoderoso."],
  7: ["El SEÑOR omnipotente me mostró esta visión: Empezaba a crecer la hierba después de la siega que corresponde al rey, y vi al Señor preparando enjambres de langostas.","Cuando las langostas acababan con la hierba de la tierra, exclamé: —¡SEÑOR mi Dios, te ruego que perdones a Jacob! ¿Cómo va a sobrevivir, si es tan pequeño?","Entonces el SEÑOR se compadeció y dijo: —Esto no va a suceder.","El SEÑOR omnipotente me mostró entonces otra visión: Vi al SEÑOR llamar a juicio con un fuego que devoraba el gran abismo y consumía los campos.","Y exclamé: —¡Detente, SEÑOR mi Dios, te lo ruego! ¿Cómo sobrevivirá Jacob, si es tan pequeño?","Entonces el SEÑOR se compadeció y dijo: —Esto tampoco va a suceder.","El Señor me mostró otra visión: Estaba él de pie junto a un muro construido a plomo, y tenía una cuerda de plomada en la mano.","Y el SEÑOR me preguntó: —¿Qué ves, Amós? —Una cuerda de plomada —respondí. Entonces el Señor dijo: —Mira, voy a tirar la plomada en medio de mi pueblo Israel; no volveré a perdonarlo.","»Los altares paganos de Isaac serán destruidos, y arruinados los santuarios de Israel; me levantaré con espada contra el palacio de Jeroboán».","Entonces Amasías, sacerdote de Betel, envió un mensaje a Jeroboán rey de Israel: «Amós está conspirando contra ti en medio de Israel. El país ya no aguanta tanta palabrería de Amós,","porque anda diciendo: »“Jeroboán morirá a espada, e Israel será llevado cautivo lejos de su tierra”».","Entonces Amasías le dijo a Amós: —¡Largo de aquí, vidente! ¡Si quieres ganarte el pan profetizando, vete a la tierra de Judá!","No vuelvas a profetizar en Betel, porque este es el santuario del rey; es el templo del reino.","Amós le respondió a Amasías: —Yo no soy profeta ni hijo de profeta, sino que cuido ovejas y cultivo higueras.","Pero el SEÑOR me sacó de detrás del rebaño y me dijo: “Ve y profetiza a mi pueblo Israel”.","Así que oye la palabra del SEÑOR. Tú dices: »“No profetices contra Israel; deja de predicar contra los descendientes de Isaac”.","»Por eso, así dice el SEÑOR: »“Tu esposa se prostituirá en la ciudad, y tus hijos y tus hijas caerán a espada. Tu tierra será medida y repartida, y tú mismo morirás en un país pagano. E Israel será llevado cautivo lejos de su tierra”»."],
  8: ["El SEÑOR omnipotente me mostró en una visión una canasta de fruta madura,","y me preguntó: —¿Qué ves, Amós? —Una canasta de fruta madura —respondí. Entonces el SEÑOR me dijo: —Ha llegado el tiempo de que Israel caiga como fruta madura; no volveré a perdonarlo.","»En aquel día —afirma el SEÑOR omnipotente—, las canciones del palacio se volverán lamentos. ¡Muchos serán los cadáveres tirados por todas partes! ¡Silencio!»","Oigan esto, los que pisotean a los necesitados y exterminan a los pobres de la tierra.","Ustedes dicen: «¿Cuándo pasará la fiesta de luna nueva para que podamos vender grano, o el día de reposo para que pongamos a la venta el trigo?» Ustedes buscan achicar la medida y aumentar el precio, falsear las balanzas","y vender los deshechos del trigo, comprar al desvalido por dinero, y al necesitado, por un par de sandalias.","Jura el SEÑOR por el orgullo de Jacob: «Jamás olvidaré nada de lo que han hecho.","»¿Y con todo esto no temblará la tierra? ¿No se enlutarán sus habitantes? Subirá la tierra entera como el Nilo; se agitará y bajará, como el río de Egipto.","»En aquel día —afirma el SEÑOR omnipotente—, »haré que el sol se ponga al mediodía, y que en pleno día la tierra se oscurezca.","Convertiré en luto sus fiestas religiosas, y en cantos fúnebres todas sus canciones. Los vestiré de luto y les afeitaré la cabeza. Será como si lloraran la muerte de un hijo único, y terminarán el día en amargura.","»Vienen días —afirma el SEÑOR omnipotente—, en que enviaré hambre al país; no será hambre de pan ni sed de agua, sino hambre de oír las palabras del SEÑOR.","La gente vagará sin rumbo de mar a mar; andarán errantes del norte al este, buscando la palabra del SEÑOR, pero no la encontrarán.","»En aquel día se desmayarán de sed las jóvenes hermosas y los jóvenes fuertes.","Y caerán para no levantarse jamás los que juran por la culpa[9] de Samaria, los que dicen: “¡Por la vida de tu dios, oh Dan! ¡Por la vida de tu dios, Berseba!”»[10]"],
  9: ["Vi al Señor de pie junto al altar, y él dijo: «Golpea los capiteles de las columnas para que se estremezcan los umbrales, y que caigan en pedazos sobre sus cabezas. A los que queden los mataré a espada. Ni uno solo escapará, ninguno saldrá con vida.","Aunque se escondan en lo profundo del sepulcro, de allí los sacará mi mano. Aunque suban hasta el cielo, de allí los derribaré.","Aunque se oculten en la cumbre del Carmelo, allí los buscaré y los atraparé. Aunque de mí se escondan en el fondo del mar, allí ordenaré a la serpiente que los muerda.","Aunque vayan al destierro arriados por sus enemigos, allí ordenaré que los mate la espada. Para mal, y no para bien, fijaré en ellos mis ojos».","El SEÑOR omnipotente, el Todopoderoso, toca la tierra, y ella se desmorona. Sube y baja la tierra como las aguas del Nilo, el río de Egipto, y se enlutan todos los que en ella viven.","Dios construye su excelso palacio en el cielo y pone su cimiento[11] en la tierra, llama a las aguas del mar y las derrama sobre la superficie de la tierra: su nombre es el SEÑOR.","«Israelitas, ¿acaso ustedes no son para mí como cusitas? ¿Acaso no saqué de Egipto a Israel, de Creta[12] a los filisteos y de Quir a los sirios? —afirma el SEÑOR—.","Por eso los ojos del SEÑOR omnipotente están sobre este reino pecaminoso. Borraré de la faz de la tierra a los descendientes de Jacob, aunque no del todo —afirma el SEÑOR—.","Daré la orden de zarandear al pueblo de Israel entre todas las naciones, como se zarandea la arena en una criba, sin que caiga a tierra ni una sola piedra.","Morirán a filo de espada todos los pecadores de mi pueblo, todos los que dicen: “No nos alcanzará la calamidad; ¡jamás se nos acercará!”","»En aquel día levantaré la choza caída de David. Repararé sus grietas, restauraré sus ruinas y la reconstruiré tal como era en días pasados,","para que ellos posean el remanente de Edom y todas las naciones que llevan mi nombre —afirma el SEÑOR, que hará estas cosas—.","»Vienen días —afirma el SEÑOR—, »en los cuales el que ara alcanzará al segador y el que pisa las uvas, al sembrador. Los montes destilarán vino dulce, el cual correrá por todas las colinas.","Restauraré a[13] mi pueblo Israel; ellos reconstruirán las ciudades arruinadas y vivirán en ellas. Plantarán viñedos y beberán su vino; cultivarán huertos y comerán sus frutos.","Plantaré a Israel en su propia tierra, para que nunca más sea arrancado de la tierra que yo le di», dice el SEÑOR tu Dios."],
};
